// Initialise le polling avec compteur d'itérations
const inp = $input.first().json;
return [{ json: {
  batch_id:      inp.batch_id,
  agent_name:    inp.agent_name,
  custom_id:     inp.custom_id,
  course_id:     inp.course_id,
  chapter_index: inp.chapter_index,
  chunk_index:   inp.chunk_index,
  pipeline_meta: inp.pipeline_meta || {},
  poll_count:    0,
  max_polls:     96,   // 96 × 15min = 24h max
  poll_interval_ms: 900000  // 15 minutes
}}];

const resp      = $('Get Batch Status').first().json;
const init      = $('Init Polling').first().json;
const pollCount = ($input.first().json.poll_count || 0) + 1;

const status = resp.status; // queued | in_progress | completed | failed | expired | cancelled

return [{ json: {
  batch_id:          resp.id,
  status,
  poll_count:        pollCount,
  max_polls:         init.max_polls,
  output_file_id:    resp.output_file_id  || null,
  error_file_id:     resp.error_file_id   || null,
  request_counts:    resp.request_counts  || {},
  agent_name:        init.agent_name,
  custom_id:         init.custom_id,
  course_id:         init.course_id,
  chapter_index:     init.chapter_index,
  chunk_index:       init.chunk_index,
  pipeline_meta:     init.pipeline_meta,
  timed_out:         pollCount >= init.max_polls
}}];

// Parse the JSONL output from OpenAI Batch API
const rawContent = $('Get Output File').first().json;
const meta = $('Check & Route').first().json;

// OpenAI returns the file content directly
const content = rawContent.body || rawContent;
let resultText = '';

if (typeof content === 'string') {
  resultText = content;
} else if (content && content.data) {
  resultText = Buffer.from(content.data).toString('utf-8');
}

// Parse JSONL (one JSON object per line)
const lines = resultText.trim().split('\n').filter(l => l.trim());
const results = lines.map(line => {
  try { return JSON.parse(line); } catch(e) { return null; }
}).filter(Boolean);

// Extract the actual response content
const parsed = results.map(r => {
  const choice = r?.response?.body?.choices?.[0];
  const content = choice?.message?.content || '';
  let parsed_content = null;
  try { parsed_content = JSON.parse(content); } catch(e) { parsed_content = content; }
  return {
    custom_id:      r.custom_id,
    parsed_content,
    finish_reason:  choice?.finish_reason,
    usage:          r?.response?.body?.usage || {}
  };
});

return [{ json: {
  status:        'completed',
  batch_id:      meta.batch_id,
  agent_name:    meta.agent_name,
  custom_id:     meta.custom_id,
  course_id:     meta.course_id,
  chapter_index: meta.chapter_index,
  chunk_index:   meta.chunk_index,
  pipeline_meta: meta.pipeline_meta,
  results:       parsed,
  agent_output:  parsed[0]?.parsed_content || null,  // shortcut for single-request batches
  usage:         parsed[0]?.usage || {},
  poll_count:    meta.poll_count
}}];

const meta = $input.first().json;
const rc = meta.request_counts || {};
const allFailed = rc.total > 0 && rc.completed === 0;
return [{ json: {
  status:        meta.timed_out ? 'timed_out' : 'failed',
  batch_id:      meta.batch_id,
  agent_name:    meta.agent_name,
  course_id:     meta.course_id,
  chapter_index: meta.chapter_index,
  chunk_index:   meta.chunk_index,
  error:         meta.timed_out
                   ? `Batch did not complete within 24h (${meta.poll_count} polls)`
                   : allFailed
                   ? `Batch completed but ALL ${rc.total} requests failed — check error_file_id: ${meta.error_file_id}`
                   : `Batch status: ${meta.status}`,
  error_file_id: meta.error_file_id || null,
  request_counts: rc,
  escalation: true
}}];

